import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        // User input (simulated)
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Proper handling of user input by escaping special characters
        String output = "<div>" + StringEscapeUtils.escapeHtml4(userInput) + "</div>";

        // Write the output to an HTML file
        try {
            File file = new File("index.html");
            FileWriter writer = new FileWriter(file);
            writer.write(output);
            writer.close();
            System.out.println("Output generated successfully!");
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

